SELECT dataset_name, last_updated
FROM datasets
WHERE dsid = '1';

SELECT CUME_DIST() OVER (ORDER BY number_of_observations) AS cumulative_distribution
FROM datasets
ORDER BY cumulative_distribution;

SELECT AVG(correlation_value) AS average_correlation
FROM correlation_metrics
WHERE corr_type = 'corr_unemp';

SELECT COUNT(dsid) AS updated_datasets_count
FROM updates
WHERE update_date >= DATE('now', '-1 month');

SELECT dsid, number_of_observations
FROM datasets
ORDER BY number_of_observations DESC;
